import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import CoursesPage from "./pages/CoursesPage/CoursesPage";
import CoursePage from "./pages/CoursePage/CoursePage";
import CoursePageAuthenticated from "./pages/CoursePageAuthenticated/CoursePageAuthenticated";
import ProfilePage from "./pages/ProfilePage/ProfilePage";
import AuthModal from "./components/AuthModal/AuthModal";

interface User {
  email: string;
  password: string;
  name: string;
}

function App() {
  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const handleLogin = (email: string, password: string) => {
    const user = users.find(
      (u) => u.email === email && u.password === password,
    );
    if (user) {
      setCurrentUser(user);
      setIsAuthenticated(true);
      setIsAuthOpen(false);
      return true;
    }
    return false;
  };

  const handleRegister = (email: string, password: string, name: string) => {
    const existingUser = users.find((u) => u.email === email);
    if (existingUser) {
      return false;
    }
    const newUser = { email, password, name };
    setUsers([...users, newUser]);
    setCurrentUser(newUser);
    setIsAuthenticated(true);
    setIsAuthOpen(false);
    return true;
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="App">
        <Routes>
          {/* Главная страница */}
          <Route
            path="/"
            element={
              <CoursesPage
                isAuthenticated={isAuthenticated}
                userName={currentUser?.name || "Anna"}
                userEmail={currentUser?.email || "anna@mail.com"}
                onLoginClick={() => setIsAuthOpen(true)}
              />
            }
          />

          {/* Страница курса для неавторизованного пользователя */}
          <Route
            path="/course/:id"
            element={<CoursePage onLoginClick={() => setIsAuthOpen(true)} />}
          />

          {/* Страница курса для авторизованного пользователя */}
          <Route
            path="/course/:id/authenticated"
            element={
              <CoursePageAuthenticated
                userName={currentUser?.name || "Anna"}
                userEmail={currentUser?.email || "anna@mail.com"}
                onProfileClick={() => {}}
                onLogout={handleLogout}
                onAddCourse={() => {}}
              />
            }
          />

          {/* Страница профиля */}
          <Route path="/profile" element={<ProfilePage />} />
        </Routes>

        <AuthModal
          isOpen={isAuthOpen}
          onClose={() => setIsAuthOpen(false)}
          onLogin={handleLogin}
          onRegister={handleRegister}
        />
      </div>
    </Router>
  );
}

export default App;
